import React, { useState } from "react";
import ModelSelector from "../components/ModelSelector";
import HyperParameters, { MODEL_PARAMS } from "../components/HyperParameters";
import TrainingResults from "../components/TrainingResults";
import RandomForestAnalysis from "../components/RandomForestAnalysis";
import { trainModel, uploadDataset } from "../services/api";

const NAV_TABS = [
  { id: 'train',    label: 'Entraînement', icon: '🚀' },
  { id: 'tache4',   label: 'Tâche 4 — RF', icon: '🌲' },
  { id: 'history',  label: 'Historique',   icon: '📜' },
];

export default function Dashboard({ allResults, onTrainComplete, onNotify }) {
  const [selectedModels, setSelectedModels] = useState(["random_forest"]);
  const [compareMode, setCompareMode]       = useState(false);
  const [training, setTraining]             = useState(false);
  const [progress, setProgress]             = useState(0);
  const [params, setParams]                 = useState({});
  const [navTab, setNavTab]                 = useState('train');

  const activeModel = selectedModels[0];
  const updateParams = (newParams) =>
    setParams((prev) => ({ ...prev, [activeModel]: newParams }));

  const handleTrain = async () => {
    setTraining(true);
    setProgress(0);
    try {
      const results = {};
      for (const m of selectedModels) {
        const res = await trainModel({ model: m, hyperparams: params[m] || {} });
        results[m] = res;
        setProgress((prev) => prev + 100 / selectedModels.length);
      }
      setProgress(100);
      onTrainComplete(results);
      onNotify("✅ Entraînement terminé !", "success");
    } catch (err) {
      onNotify("❌ Erreur d'entraînement", "error");
    } finally {
      setTraining(false);
      setProgress(0);
    }
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const formData = new FormData();
    formData.append("file", file);
    try {
      await uploadDataset(formData);
      onNotify("✅ Dataset uploadé !", "success");
    } catch {
      onNotify("❌ Échec de l'upload", "error");
    }
  };

  return (
    <div className="min-h-screen bg-gray-950 text-white">
      {/* ── Top Nav ── */}
      <div className="border-b border-white/10 bg-gray-950/80 backdrop-blur sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-6 flex items-center gap-1 h-12">
          {NAV_TABS.map(tab => (
            <button
              key={tab.id}
              onClick={() => setNavTab(tab.id)}
              className={`flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all
                ${navTab === tab.id
                  ? tab.id === 'tache4'
                    ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30'
                    : 'bg-blue-500/20 text-blue-400 border border-blue-500/30'
                  : 'text-gray-400 hover:text-gray-200'}`}
            >
              <span>{tab.icon}</span>
              <span>{tab.label}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-6">

        {/* ══ TAB : ENTRAÎNEMENT ══ */}
        {navTab === 'train' && (
          <div className="grid grid-cols-1 lg:grid-cols-[320px_1fr] gap-6">
            {/* Sidebar gauche */}
            <div className="space-y-6">
              {/* Model selector */}
              <div className="bg-white/3 border border-white/8 rounded-2xl p-5">
                <ModelSelector
                  selected={selectedModels}
                  onChange={setSelectedModels}
                  compareMode={compareMode}
                  onCompareModeChange={setCompareMode}
                />
              </div>

              {/* Hyperparams */}
              <div className="bg-white/3 border border-white/8 rounded-2xl p-5">
                <HyperParameters
                  modelId={activeModel}
                  params={params[activeModel] || {}}
                  onChange={updateParams}
                  onNotify={onNotify}
                />
              </div>

              {/* Upload */}
              <div className="bg-white/3 border border-white/8 rounded-2xl p-5 space-y-3">
                <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest">
                  📂 Dataset
                </h2>
                <label className="flex flex-col items-center gap-2 cursor-pointer border-2 border-dashed border-white/10 rounded-xl p-4 hover:border-blue-500/40 transition-all">
                  <span className="text-2xl">☁️</span>
                  <span className="text-xs text-gray-400">Glisser ou cliquer pour uploader</span>
                  <span className="text-xs text-gray-600">.csv · .data</span>
                  <input type="file" className="hidden" onChange={handleUpload} accept=".csv,.data"/>
                </label>
              </div>

              {/* Train button */}
              <button
                onClick={handleTrain}
                disabled={training}
                className="w-full py-3.5 text-sm font-bold rounded-xl bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-500 hover:to-blue-400 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-blue-500/20 flex items-center justify-center gap-2"
              >
                {training ? (
                  <>
                    <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24" fill="none">
                      <circle cx="12" cy="12" r="10" stroke="currentColor" strokeOpacity="0.3" strokeWidth="3"/>
                      <path d="M12 2a10 10 0 0 1 10 10" stroke="currentColor" strokeWidth="3" strokeLinecap="round"/>
                    </svg>
                    Entraînement… {Math.round(progress)}%
                  </>
                ) : (
                  <>🚀 Lancer l'entraînement</>
                )}
              </button>

              {/* Progress bar */}
              {training && (
                <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-blue-500 rounded-full transition-all duration-300"
                    style={{ width: `${progress}%` }}
                  />
                </div>
              )}
            </div>

            {/* Résultats droite */}
            <div className="bg-white/3 border border-white/8 rounded-2xl p-5">
              <TrainingResults results={allResults} onNotify={onNotify} />
            </div>
          </div>
        )}

        {/* ══ TAB : TÂCHE 4 ══ */}
        {navTab === 'tache4' && (
          <div className="grid grid-cols-1 lg:grid-cols-[1fr_380px] gap-6">
            {/* Analyse principale */}
            <div className="bg-white/3 border border-white/8 rounded-2xl p-5">
              <RandomForestAnalysis trainingResults={allResults} />
            </div>

            {/* Résumé / légende droite */}
            <div className="space-y-4">
              {/* Résumé métriques RF */}
              <div className="bg-emerald-500/5 border border-emerald-500/20 rounded-2xl p-5 space-y-4">
                <h3 className="text-sm font-bold text-emerald-400">🌲 Random Forest — Résumé</h3>
                {[
                  { label: 'Accuracy',  val: allResults?.random_forest?.accuracy  ?? 69.50, color: 'text-blue-400'   },
                  { label: 'F1 Score',  val: allResults?.random_forest?.f1        ?? 82.01, color: 'text-emerald-400'},
                  { label: 'ROC AUC',   val: allResults?.random_forest?.roc_auc   ?? 74.30, color: 'text-purple-400' },
                  { label: 'Precision', val: allResults?.random_forest?.precision ?? 70.20, color: 'text-yellow-400' },
                  { label: 'Recall',    val: allResults?.random_forest?.recall    ?? 98.58, color: 'text-red-400'    },
                ].map(m => (
                  <div key={m.label} className="flex items-center justify-between">
                    <span className="text-xs text-gray-400">{m.label}</span>
                    <span className={`text-sm font-black font-mono ${m.color}`}>
                      {m.val?.toFixed ? m.val.toFixed(1) : m.val}%
                    </span>
                  </div>
                ))}
              </div>

              {/* Conclusions clés */}
              <div className="bg-white/3 border border-white/8 rounded-2xl p-5 space-y-3">
                <h3 className="text-sm font-bold text-gray-300">📋 Conclusions Clés</h3>
                {[
                  { icon: '📊', title: 'Top Feature', desc: 'CreditAmount (10.02%) est la variable la plus discriminante' },
                  { icon: '🎯', title: 'Stabilité', desc: 'Écart-type de 0.72% sur 10 random_states → modèle robuste' },
                  { icon: '⚠️', title: 'Biais de classe', desc: '59 FP vs 2 FN — biais vers l\'approbation (70/30 déséquilibre)' },
                  { icon: '⚖️', title: 'Meilleur config', desc: 'n=100, depth=5 offre le meilleur compromis biais-variance' },
                  { icon: '🔄', title: 'vs DTree', desc: 'RF surpasse DT de +10% accuracy et +26.95% recall' },
                ].map(item => (
                  <div key={item.title} className="flex gap-3">
                    <span className="text-base flex-shrink-0 mt-0.5">{item.icon}</span>
                    <div>
                      <div className="text-xs font-bold text-gray-300">{item.title}</div>
                      <div className="text-xs text-gray-500 mt-0.5 leading-relaxed">{item.desc}</div>
                    </div>
                  </div>
                ))}
              </div>

              {/* MLflow status */}
              <div className="bg-white/3 border border-white/8 rounded-2xl p-4 flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-emerald-500/20 flex items-center justify-center text-emerald-400 text-lg">📡</div>
                <div>
                  <div className="text-xs font-bold text-gray-300">MLflow Tracking</div>
                  <div className="text-xs text-gray-500">Tous les runs loggés sur <span className="font-mono text-emerald-400">localhost:5000</span></div>
                </div>
                <div className="ml-auto w-2 h-2 rounded-full bg-emerald-400 animate-pulse"/>
              </div>
            </div>
          </div>
        )}

        {/* ══ TAB : HISTORIQUE ══ */}
        {navTab === 'history' && (
          <div className="bg-white/3 border border-white/8 rounded-2xl p-5">
            <TrainingResults results={allResults} onNotify={onNotify} />
          </div>
        )}
      </div>
    </div>
  );
}
